mapper.select:
SELECT admin_no
FROM tbl_admin_account
WHERE admin_id = #{adminId}
  AND admin_pw = #{adminPw}

mapper.update:
UPDATE tbl_user
SET user_status = 1,
    organ_no    = #{organNo}
WHERE user_no = #{userNo}

mapper.delete:
DELETE FROM TBL_USER
WHERE user_no = #{userNo}
  AND user_status = 2
